import React from 'react';
import { NavLink } from 'react-router-dom';

const SignOutLinks = () => {
  return(
    <ul className="">
      <li><NavLink to="/signup">Sign Up</NavLink></li>
      <li><NavLink to="/signin">Log In</NavLink></li>
    </ul>
  )
}

export default SignOutLinks;
